{
 "level": "A2–B1",
 "intro": "In this guide, you will learn to <strong>distinguish between the main ways of talking about the future</strong> and choose the form depending on meaning.",
 "rules": [
 {
 "label": "WILL",
 "color": "blue",
 "text": "Spontaneous decisions, promises, requests, neutral predictions:",
 "example": "I'll help you. / I think it will rain."
 },
 {
 "label": "BE GOING TO",
 "color": "emerald",
 "text": "Plans and predictions based on what is seen now:",
 "example": "I'm going to call her. Look at those clouds! meanings:"
 },
 {
 "label": "KEY IDEA",
 "color": "amber",
 "text": "Use the pattern in the examples and focus on the highlighted words.",
 "example": "moment now / plan before / evidence now"
 }
 ]
}

{
 "title": "What you will study here",
 "intro": "Future forms cover several common meanings. Focus on why the speaker chooses the form, not only on the future time.",
 "rows": [
 {
 "en": "Will",
 "ua": "Will",
 "note": "spontaneous decisions, promises, opinions and predictions: I'll answer it. / I think she will arrive."
 },
 {
 "en": "Be going to",
 "ua": "Be going to",
 "note": "intentions or plans that already exist: We're going to move house."
 },
 {
 "en": "Be going to",
 "ua": "Be going to",
 "note": "predictions based on present evidence: Look at the clouds. It's going to rain."
 },
 {
 "en": "Choice of form",
 "ua": "Choice of form",
 "note": "The same future event can sound different when the reason changes."
 }
 ],
 "warning": "With future forms, ask: is this a decision now, an existing plan, an opinion, or evidence I can see?"
}

{
 "title": "What to pay attention to",
 "items": [
 "If the decision arose <strong>right now</strong>, we usually choose <strong>will</strong>.",
 "If the plan was <strong>before the moment of speech</strong>, usually we choose <strong>be going to</strong>.",
 "If it is an <strong>opinion or assumption</strong> without direct evidence, we often use <strong>will</strong>.",
 "If there is <strong>visible evidence</strong> now, we often use <strong>be going to</strong>."
 ]
}
